CREATE TYPE "BusinessRuleStatus" AS ENUM ('DRAFT','PUBLISHED','ARCHIVED');
CREATE TYPE "BusinessRuleExecutionStatus" AS ENUM ('MATCHED','NOT_MATCHED','FAILED','DRY_RUN');
CREATE TABLE "BusinessRuleDefinition" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"key" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"status" "BusinessRuleStatus" NOT NULL DEFAULT 'DRAFT',"activeVersionId" TEXT,"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "BusinessRuleVersion" ("id" TEXT PRIMARY KEY,"definitionId" TEXT NOT NULL,"version" INTEGER NOT NULL,"conditions" JSONB NOT NULL,"actions" JSONB NOT NULL,"priority" INTEGER NOT NULL DEFAULT 100,"stopOnMatch" BOOLEAN NOT NULL DEFAULT false,"publishedAt" TIMESTAMP(3),"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "BusinessRuleExecution" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"definitionId" TEXT NOT NULL,"versionId" TEXT NOT NULL,"status" "BusinessRuleExecutionStatus" NOT NULL,"entityType" TEXT,"entityId" TEXT,"triggerType" TEXT,"context" JSONB NOT NULL,"matched" BOOLEAN NOT NULL,"actionResults" JSONB NOT NULL DEFAULT '[]',"error" TEXT,"executedById" TEXT,"executedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "BusinessRuleDefinition_organizationId_key_key" ON "BusinessRuleDefinition"("organizationId","key"); CREATE UNIQUE INDEX "BusinessRuleVersion_definitionId_version_key" ON "BusinessRuleVersion"("definitionId","version");
ALTER TABLE "BusinessRuleDefinition" ADD CONSTRAINT "BusinessRuleDefinition_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE;
ALTER TABLE "BusinessRuleVersion" ADD CONSTRAINT "BusinessRuleVersion_definitionId_fkey" FOREIGN KEY ("definitionId") REFERENCES "BusinessRuleDefinition"("id") ON DELETE CASCADE;
ALTER TABLE "BusinessRuleExecution" ADD CONSTRAINT "BusinessRuleExecution_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE;
ALTER TABLE "BusinessRuleExecution" ADD CONSTRAINT "BusinessRuleExecution_definitionId_fkey" FOREIGN KEY ("definitionId") REFERENCES "BusinessRuleDefinition"("id") ON DELETE CASCADE;
ALTER TABLE "BusinessRuleExecution" ADD CONSTRAINT "BusinessRuleExecution_versionId_fkey" FOREIGN KEY ("versionId") REFERENCES "BusinessRuleVersion"("id");
